      "id": "senior-community-service-employment",
      "name": "Senior Community Service Employment Program (SCSEP)",
      "shortName": "SCSEP Employment",
      "tagline": "Part-time paid training positions for unemployed adults 55+ earning $300-400+ per week while building job skills",
